"""
Parameterized generator for GH948_gpytorch_2172.

Source PR:    https://github.com/cornellius-gp/gpytorch/pull/2172
Source Issue: https://github.com/cornellius-gp/gpytorch/issues/2072

Seed varies: renames 'add_jitter' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH948_gpytorch_2172'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH948_gpytorch_2172'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('add_jitter', 'add_jitter' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH948_gpytorch_2172',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'cornellius-gp/gpytorch',
                "pr_number": 2172,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/cornellius-gp/gpytorch/pull/2172",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'gpytorch/distributions/multitask_multivariate_normal.py': '#!/usr/bin/env python3\n\nimport torch\nfrom linear_operator import LinearOperator, to_linear_operator\nfrom linear_operator.operators import BlockDiagLinearOperator, BlockInterleavedLinearOperator, CatLinearOperator\n\nfrom .multivariate_normal import MultivariateNormal\n\n\nclass MultitaskMultivariateNormal(MultivariateNormal):\n    """\n    Constructs a multi-output multivariate Normal random variable, based on mean and covariance\n    Can be multi-output multivariate, or a batch of multi-output multivariate Normal\n\n    Passing a matrix mean corresponds to a multi-output multivariate Normal\n    Passing a matrix mean corresponds to a batch of multivariate Normals\n\n    :param torch.Tensor mean:  An `n x t` or batch `b x n x t` matrix of means for the MVN distribution.\n    :param ~linear_operator.operators.LinearOperator covar: An `... x NT x NT` (batch) matrix.\n        covariance matrix of MVN distribution.\n    :param bool validate_args: (default=False) If True, validate `mean` anad `covariance_matrix` arguments.\n    :param bool interleaved: (default=True) If True, covariance matrix is interpreted as block-diagonal w.r.t.\n        inter-task covariances for each observation. If False, it is interpreted as block-diagonal\n        w.r.t. inter-observation covariance for each task.\n    """\n\n    def __init__(self, mean, covariance_matrix, validate_args=False, interleaved=True):\n        if not torch.is_tensor(mean) and not isinstance(mean, LinearOperator):\n            raise RuntimeError("The mean of a MultitaskMultivariateNormal must be a Tensor or LinearOperator")\n\n        if not torch.is_tensor(covariance_matrix) and not isinstance(covariance_matrix, LinearOperator):\n            raise RuntimeError("The covariance of a MultitaskMultivariateNormal must be a Tensor or LinearOperator")\n\n        if mean.dim() < 2:\n            raise RuntimeError("mean should be a matrix or a batch matrix (batch mode)")\n\n        # Ensure that shapes are broadcasted appropriately across the mean and covariance\n        # Means can have singleton dimensions for either the `n` or `t` dimensions\n        batch_shape = torch.broadcast_shapes(mean.shape[:-2], covariance_matrix.shape[:-2])\n        if mean.shape[-2:].numel() != covariance_matrix.size(-1):\n            if covariance_matrix.size(-1) % mean.shape[-2:].numel():\n                raise RuntimeError(\n                    f"mean shape {mean.shape} is incompatible with covariance shape {covariance_matrix.shape}"\n                )\n            elif mean.size(-2) == 1:\n                mean = mean.expand(*batch_shape, covariance_matrix.size(-1) // mean.size(-1), mean.size(-1))\n            elif mean.size(-1) == 1:\n                mean = mean.expand(*batch_shape, mean.size(-2), covariance_matrix.size(-2) // mean.size(-2))\n            else:\n                raise RuntimeError(\n                    f"mean shape {mean.shape} is incompatible with covariance shape {covariance_matrix.shape}"\n                )\n        else:\n            mean = mean.expand(*batch_shape, *mean.shape[-2:])\n\n        self._output_shape = mean.shape\n        # TODO: Instead of transpose / view operations, use a PermutationLinearOperator (see #539)\n        # to handle interleaving\n        self._interleaved = interleaved\n        if self._interleaved:\n            mean_mvn = mean.reshape(*mean.shape[:-2], -1)\n        else:\n            mean_mvn = mean.transpose(-1, -2).reshape(*mean.shape[:-2], -1)\n        super().__init__(mean=mean_mvn, covariance_matrix=covariance_matrix, validate_args=validate_args)\n\n    @property\n    def base_sample_shape(self):\n        """\n        Returns the shape of a base sample (without batching) that is used to\n        generate a single sample.\n        """\n        base_sample_shape = self.event_shape\n        return base_sample_shape\n\n    @property\n    def event_shape(self):\n        return self._output_shape[-2:]\n\n    @classmethod\n    def from_batch_mvn(cls, batch_mvn, task_dim=-1):\n        """\n        Reinterprate a batch of multivariate normal distributions as an (independent) multitask multivariate normal\n        distribution.\n\n        :param ~gpytorch.distributions.MultivariateNormal batch_mvn: The base MVN distribution.\n            (This distribution should have at least one batch dimension).\n        :param int task_dim: Which batch dimension should be interpreted as the dimension for the independent tasks.\n        :returns: the independent multitask distribution\n        :rtype: gpytorch.distributions.MultitaskMultivariateNormal\n\n        Example:\n            >>> # model is a gpytorch.models.VariationalGP\n            >>> # likelihood is a gpytorch.likelihoods.Likelihood\n            >>> mean = torch.randn(4, 2, 3)\n            >>> covar_factor = torch.randn(4, 2, 3, 3)\n            >>> covar = covar_factor @ covar_factor.transpose(-1, -2)\n            >>> mvn = gpytorch.distributions.MultivariateNormal(mean, covar)\n            >>> print(mvn.event_shape, mvn.batch_shape)\n            >>> # torch.Size([3]), torch.Size([4, 2])\n            >>>\n            >>> mmvn = MultitaskMultivariateNormal.from_batch_mvn(mvn, task_dim=-1)\n            >>> print(mmvn.event_shape, mmvn.batch_shape)\n            >>> # torch.Size([3, 2]), torch.Size([4])\n        """\n        orig_task_dim = task_dim\n        task_dim = task_dim if task_dim >= 0 else (len(batch_mvn.batch_shape) + task_dim)\n        if task_dim < 0 or task_dim > len(batch_mvn.batch_shape):\n            raise ValueError(\n                f"task_dim of {orig_task_dim} is incompatible with MVN batch shape of {batch_mvn.batch_shape}"\n            )\n\n        num_dim = batch_mvn.mean.dim()\n        res = cls(\n            mean=batch_mvn.mean.permute(*range(0, task_dim), *range(task_dim + 1, num_dim), task_dim),\n            covariance_matrix=BlockInterleavedLinearOperator(batch_mvn.lazy_covariance_matrix, block_dim=task_dim),\n        )\n        return res\n\n    @classmethod\n    def from_independent_mvns(cls, mvns):\n        """\n        Convert an iterable of MVNs into a :obj:`~gpytorch.distributions.MultitaskMultivariateNormal`.\n        The resulting distribution will have ``len(mvns)`` tasks, and the tasks will be independent.\n\n        :param ~gpytorch.distributions.MultitaskNormal mvn: The base MVN distributions.\n        :returns: the independent multitask distribution\n        :rtype: gpytorch.distributions.MultitaskMultivariateNormal\n\n        Example:\n            >>> # model is a gpytorch.models.VariationalGP\n            >>> # likelihood is a gpytorch.likelihoods.Likelihood\n            >>> mean = torch.randn(4, 3)\n            >>> covar_factor = torch.randn(4, 3, 3)\n            >>> covar = covar_factor @ covar_factor.transpose(-1, -2)\n            >>> mvn1 = gpytorch.distributions.MultivariateNormal(mean, covar)\n            >>>\n            >>> mean = torch.randn(4, 3)\n            >>> covar_factor = torch.randn(4, 3, 3)\n            >>> covar = covar_factor @ covar_factor.transpose(-1, -2)\n            >>> mvn2 = gpytorch.distributions.MultivariateNormal(mean, covar)\n            >>>\n            >>> mmvn = MultitaskMultivariateNormal.from_independent_mvns([mvn1, mvn2])\n            >>> print(mmvn.event_shape, mmvn.batch_shape)\n            >>> # torch.Size([3, 2]), torch.Size([4])\n        """\n        if len(mvns) < 2:\n            raise ValueError("Must provide at least 2 MVNs to form a MultitaskMultivariateNormal")\n        if any(isinstance(mvn, MultitaskMultivariateNormal) for mvn in mvns):\n            raise ValueError("Cannot accept MultitaskMultivariateNormals")\n        if not all(m.batch_shape == mvns[0].batch_shape for m in mvns[1:]):\n            raise ValueError("All MultivariateNormals must have the same batch shape")\n        if not all(m.event_shape == mvns[0].event_shape for m in mvns[1:]):\n            raise ValueError("All MultivariateNormals must have the same event shape")\n        mean = torch.stack([mvn.mean for mvn in mvns], -1)\n        # TODO: To do the following efficiently, we don\'t want to evaluate the\n        # covariance matrices. Instead, we want to use the lazies directly in the\n        # BlockDiagLinearOperator. This will require implementing a new BatchLinearOperator:\n\n        # https://github.com/cornellius-gp/gpytorch/issues/468\n        covar_blocks_lazy = CatLinearOperator(\n            *[mvn.lazy_covariance_matrix.unsqueeze(0) for mvn in mvns], dim=0, output_device=mean.device\n        )\n        covar_lazy = BlockDiagLinearOperator(covar_blocks_lazy, block_dim=0)\n        return cls(mean=mean, covariance_matrix=covar_lazy, interleaved=False)\n\n    @classmethod\n    def from_repeated_mvn(cls, mvn, num_tasks):\n        """\n        Convert a single MVN into a :obj:`~gpytorch.distributions.MultitaskMultivariateNormal`,\n        where each task shares the same mean and covariance.\n\n        :param ~gpytorch.distributions.MultitaskNormal mvn: The base MVN distribution.\n        :param int num_tasks: How many tasks to create.\n        :returns: the independent multitask distribution\n        :rtype: gpytorch.distributions.MultitaskMultivariateNormal\n\n        Example:\n            >>> # model is a gpytorch.models.VariationalGP\n            >>> # likelihood is a gpytorch.likelihoods.Likelihood\n            >>> mean = torch.randn(4, 3)\n            >>> covar_factor = torch.randn(4, 3, 3)\n            >>> covar = covar_factor @ covar_factor.transpose(-1, -2)\n            >>> mvn = gpytorch.distributions.MultivariateNormal(mean, covar)\n            >>> print(mvn.event_shape, mvn.batch_shape)\n            >>> # torch.Size([3]), torch.Size([4])\n            >>>\n            >>> mmvn = MultitaskMultivariateNormal.from_repeated_mvn(mvn, num_tasks=2)\n            >>> print(mmvn.event_shape, mmvn.batch_shape)\n            >>> # torch.Size([3, 2]), torch.Size([4])\n        """\n        return cls.from_batch_mvn(mvn.expand(torch.Size([num_tasks]) + mvn.batch_shape), task_dim=0)\n\n    def expand(self, batch_size):\n        new_mean = self.mean.expand(torch.Size(batch_size) + self.mean.shape[-2:])\n        new_covar = self._covar.expand(torch.Size(batch_size) + self._covar.shape[-2:])\n        res = self.__class__(new_mean, new_covar, interleaved=self._interleaved)\n        return res\n\n    def get_base_samples(self, sample_shape=torch.Size()):\n        base_samples = super().get_base_samples(sample_shape)\n        if not self._interleaved:\n            # flip shape of last two dimensions\n            new_shape = sample_shape + self._output_shape[:-2] + self._output_shape[:-3:-1]\n            return base_samples.view(new_shape).transpose(-1, -2).contiguous()\n        return base_samples.view(*sample_shape, *self._output_shape)\n\n    def log_prob(self, value):\n        if not self._interleaved:\n            # flip shape of last two dimensions\n            new_shape = value.shape[:-2] + value.shape[:-3:-1]\n            value = value.view(new_shape).transpose(-1, -2).contiguous()\n        return super().log_prob(value.reshape(*value.shape[:-2], -1))\n\n    @property\n    def mean(self):\n        mean = super().mean\n        if not self._interleaved:\n            # flip shape of last two dimensions\n            new_shape = self._output_shape[:-2] + self._output_shape[:-3:-1]\n            return mean.view(new_shape).transpose(-1, -2).contiguous()\n        return mean.view(self._output_shape)\n\n    @property\n    def num_tasks(self):\n        return self._output_shape[-1]\n\n    def rsample(self, sample_shape=torch.Size(), base_samples=None):\n        if base_samples is not None:\n            # Make sure that the base samples agree with the distribution\n            mean_shape = self.mean.shape\n            base_sample_shape = base_samples.shape[-self.mean.ndimension() :]\n            if mean_shape != base_sample_shape:\n                raise RuntimeError(\n                    "The shape of base_samples (minus sample shape dimensions) should agree with the shape "\n                    "of self.mean. Expected ...{} but got {}".format(mean_shape, base_sample_shape)\n                )\n            sample_shape = base_samples.shape[: -self.mean.ndimension()]\n            base_samples = base_samples.view(*sample_shape, *self.loc.shape)\n\n        samples = super().rsample(sample_shape=sample_shape, base_samples=base_samples)\n        if not self._interleaved:\n            # flip shape of last two dimensions\n            new_shape = sample_shape + self._output_shape[:-2] + self._output_shape[:-3:-1]\n            return samples.view(new_shape).transpose(-1, -2).contiguous()\n        return samples.view(sample_shape + self._output_shape)\n\n    def to_data_independent_dist(self):\n        """\n        Convert a multitask MVN into a batched (non-multitask) MVNs\n        The result retains the intertask covariances, but gets rid of the inter-data covariances.\n        The resulting distribution will have ``len(mvns)`` tasks, and the tasks will be independent.\n\n        :returns: the bached data-independent MVN\n        :rtype: gpytorch.distributions.MultivariateNormal\n        """\n        # Create batch distribution where all data are independent, but the tasks are dependent\n        full_covar = self.lazy_covariance_matrix\n        num_data, num_tasks = self.mean.shape[-2:]\n        data_indices = torch.arange(0, num_data * num_tasks, num_tasks, device=full_covar.device).view(-1, 1, 1)\n        task_indices = torch.arange(num_tasks, device=full_covar.device)\n        task_covars = full_covar[\n            ..., data_indices + task_indices.unsqueeze(-2), data_indices + task_indices.unsqueeze(-1)\n        ]\n        return MultivariateNormal(self.mean, to_linear_operator(task_covars).add_jitter())\n\n    @property\n    def variance(self):\n        var = super().variance\n        if not self._interleaved:\n            # flip shape of last two dimensions\n            new_shape = self._output_shape[:-2] + self._output_shape[:-3:-1]\n            return var.view(new_shape).transpose(-1, -2).contiguous()\n        return var.view(self._output_shape)\n',
            'test/distributions/test_multitask_multivariate_normal.py': '#!/usr/bin/env python3\n\nimport math\nimport os\nimport random\nimport unittest\n\nimport torch\nfrom linear_operator.operators import DiagLinearOperator\n\nfrom gpytorch.distributions import MultitaskMultivariateNormal, MultivariateNormal\nfrom gpytorch.test.base_test_case import BaseTestCase\nfrom gpytorch.test.utils import least_used_cuda_device\n\n\nclass TestMultiTaskMultivariateNormal(BaseTestCase, unittest.TestCase):\n    def setUp(self):\n        if os.getenv("UNLOCK_SEED") is None or os.getenv("UNLOCK_SEED").lower() == "false":\n            self.rng_state = torch.get_rng_state()\n            torch.manual_seed(1)\n            if torch.cuda.is_available():\n                torch.cuda.manual_seed_all(1)\n            random.seed(1)\n\n    def tearDown(self):\n        if hasattr(self, "rng_state"):\n            torch.set_rng_state(self.rng_state)\n\n    def test_multitask_multivariate_normal_exceptions(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            mean = torch.tensor([0, 1], device=device, dtype=dtype)\n            covmat = torch.eye(2, device=device, dtype=dtype)\n            with self.assertRaises(RuntimeError):\n                MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat)\n\n    def test_multitask_multivariate_normal_exceptions_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_multitask_multivariate_normal_exceptions(cuda=True)\n\n    def test_multitask_multivariate_normal(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            mean = torch.tensor([[0, 1], [2, 3], [4, 5]], dtype=dtype, device=device)\n            variance = torch.tensor([[1, 2], [3, 4], [5, 6]], dtype=dtype, device=device)\n\n            # interleaved\n            covmat = variance.view(-1).diag_embed()\n            mtmvn = MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat)\n            self.assertTrue(torch.equal(mtmvn.mean, mean))\n            self.assertTrue(torch.allclose(mtmvn.variance, variance))\n            self.assertTrue(torch.allclose(mtmvn.scale_tril, covmat.sqrt()))\n            self.assertTrue(mtmvn.event_shape == torch.Size([3, 2]))\n            self.assertTrue(mtmvn.batch_shape == torch.Size())\n            mvn_plus1 = mtmvn + 1\n            self.assertTrue(torch.equal(mvn_plus1.mean, mtmvn.mean + 1))\n            self.assertTrue(torch.equal(mvn_plus1.covariance_matrix, mtmvn.covariance_matrix))\n            mvn_times2 = mtmvn * 2\n            self.assertTrue(torch.equal(mvn_times2.mean, mtmvn.mean * 2))\n            self.assertTrue(torch.equal(mvn_times2.covariance_matrix, mtmvn.covariance_matrix * 4))\n            mvn_divby2 = mtmvn / 2\n            self.assertTrue(torch.equal(mvn_divby2.mean, mtmvn.mean / 2))\n            self.assertTrue(torch.equal(mvn_divby2.covariance_matrix, mtmvn.covariance_matrix / 4))\n            self.assertAlmostEqual(mtmvn.entropy().item(), 11.80326, places=4)\n            self.assertAlmostEqual(\n                mtmvn.log_prob(torch.zeros(3, 2, device=device, dtype=dtype)).item(), -14.52826, places=4\n            )\n            logprob = mtmvn.log_prob(torch.zeros(2, 3, 2, device=device, dtype=dtype))\n            logprob_expected = -14.52826 * torch.ones(2, device=device, dtype=dtype)\n            self.assertTrue(torch.allclose(logprob, logprob_expected))\n            conf_lower, conf_upper = mtmvn.confidence_region()\n            self.assertTrue(torch.allclose(conf_lower, mtmvn.mean - 2 * mtmvn.stddev))\n            self.assertTrue(torch.allclose(conf_upper, mtmvn.mean + 2 * mtmvn.stddev))\n            self.assertTrue(mtmvn.sample().shape == torch.Size([3, 2]))\n            self.assertTrue(mtmvn.sample(torch.Size([3])).shape == torch.Size([3, 3, 2]))\n            self.assertTrue(mtmvn.sample(torch.Size([3, 4])).shape == torch.Size([3, 4, 3, 2]))\n\n            # non-interleaved\n            covmat = variance.transpose(-1, -2).reshape(-1).diag_embed()\n            mtmvn = MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat, interleaved=False)\n            self.assertTrue(torch.equal(mtmvn.mean, mean))\n            self.assertTrue(torch.allclose(mtmvn.variance, variance))\n            self.assertTrue(torch.allclose(mtmvn.scale_tril, covmat.sqrt()))\n            self.assertTrue(mtmvn.event_shape == torch.Size([3, 2]))\n            self.assertTrue(mtmvn.batch_shape == torch.Size())\n\n    def test_multitask_multivariate_normal_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_multitask_multivariate_normal(cuda=True)\n\n    def test_multitask_multivariate_normal_batch(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            mean = torch.tensor([[0, 1], [2, 3], [4, 5]], dtype=dtype, device=device).repeat(2, 1, 1)\n            variance = torch.tensor([[1, 2], [3, 4], [5, 6]], dtype=dtype, device=device).repeat(2, 1, 1)\n\n            # interleaved\n            covmat = variance.view(2, 1, -1) * torch.eye(6, device=device, dtype=dtype)\n            mtmvn = MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat)\n            self.assertTrue(torch.equal(mtmvn.mean, mean))\n            self.assertTrue(torch.allclose(mtmvn.variance, variance))\n            self.assertTrue(torch.allclose(mtmvn.scale_tril, covmat.sqrt()))\n            self.assertTrue(mtmvn.event_shape == torch.Size([3, 2]))\n            self.assertTrue(mtmvn.batch_shape == torch.Size([2]))\n            mvn_plus1 = mtmvn + 1\n            self.assertTrue(torch.equal(mvn_plus1.mean, mtmvn.mean + 1))\n            self.assertTrue(torch.equal(mvn_plus1.covariance_matrix, mtmvn.covariance_matrix))\n            mvn_times2 = mtmvn * 2\n            self.assertTrue(torch.equal(mvn_times2.mean, mtmvn.mean * 2))\n            self.assertTrue(torch.equal(mvn_times2.covariance_matrix, mtmvn.covariance_matrix * 4))\n            mvn_divby2 = mtmvn / 2\n            self.assertTrue(torch.equal(mvn_divby2.mean, mtmvn.mean / 2))\n            self.assertTrue(torch.equal(mvn_divby2.covariance_matrix, mtmvn.covariance_matrix / 4))\n            self.assertTrue(torch.allclose(mtmvn.entropy(), 11.80326 * torch.ones(2, device=device, dtype=dtype)))\n            logprob = mtmvn.log_prob(torch.zeros(2, 3, 2, device=device, dtype=dtype))\n            logprob_expected = -14.52826 * torch.ones(2, device=device, dtype=dtype)\n            self.assertTrue(torch.allclose(logprob, logprob_expected))\n            logprob = mtmvn.log_prob(torch.zeros(3, 2, 3, 2, device=device, dtype=dtype))\n            logprob_expected = -14.52826 * torch.ones(3, 2, device=device, dtype=dtype)\n            self.assertTrue(torch.allclose(logprob, logprob_expected))\n            conf_lower, conf_upper = mtmvn.confidence_region()\n            self.assertTrue(torch.allclose(conf_lower, mtmvn.mean - 2 * mtmvn.stddev))\n            self.assertTrue(torch.allclose(conf_upper, mtmvn.mean + 2 * mtmvn.stddev))\n            self.assertTrue(mtmvn.sample().shape == torch.Size([2, 3, 2]))\n            self.assertTrue(mtmvn.sample(torch.Size([3])).shape == torch.Size([3, 2, 3, 2]))\n            self.assertTrue(mtmvn.sample(torch.Size([3, 4])).shape == torch.Size([3, 4, 2, 3, 2]))\n\n            # non-interleaved\n            covmat = variance.transpose(-1, -2).reshape(2, 1, -1) * torch.eye(6, device=device, dtype=dtype)\n            mtmvn = MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat, interleaved=False)\n            self.assertTrue(torch.equal(mtmvn.mean, mean))\n            self.assertTrue(torch.allclose(mtmvn.variance, variance))\n            self.assertTrue(torch.allclose(mtmvn.scale_tril, covmat.sqrt()))\n            self.assertTrue(mtmvn.event_shape == torch.Size([3, 2]))\n            self.assertTrue(mtmvn.batch_shape == torch.Size([2]))\n\n    def test_multitask_multivariate_normal_batch_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_multitask_multivariate_normal_batch(cuda=True)\n\n    def test_multivariate_normal_correlated_samples(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            mean = torch.tensor([[0, 1], [2, 3], [4, 5]], dtype=dtype, device=device)\n            variance = torch.tensor([[1, 2], [3, 4], [5, 6]], dtype=dtype, device=device)\n            covmat = variance.view(-1).diag_embed()\n            mtmvn = MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat)\n            base_samples = mtmvn.get_base_samples(torch.Size([3, 4]))\n            self.assertTrue(mtmvn.sample(base_samples=base_samples).shape == torch.Size([3, 4, 3, 2]))\n            base_samples = mtmvn.get_base_samples()\n            self.assertTrue(mtmvn.sample(base_samples=base_samples).shape == torch.Size([3, 2]))\n\n    def test_multivariate_normal_correlated_samples_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_multivariate_normal_correlated_samples(cuda=True)\n\n    def test_multivariate_normal_batch_correlated_samples(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            mean = torch.tensor([[0, 1], [2, 3], [4, 5]], dtype=dtype, device=device).repeat(2, 1, 1)\n            variance = torch.tensor([[1, 2], [3, 4], [5, 6]], dtype=dtype, device=device).repeat(2, 1, 1)\n            covmat = variance.view(2, 1, -1) * torch.eye(6, device=device, dtype=dtype)\n            mtmvn = MultitaskMultivariateNormal(mean=mean, covariance_matrix=covmat)\n            base_samples = mtmvn.get_base_samples(torch.Size((3, 4)))\n            self.assertTrue(mtmvn.sample(base_samples=base_samples).shape == torch.Size([3, 4, 2, 3, 2]))\n            base_samples = mtmvn.get_base_samples()\n            self.assertTrue(mtmvn.sample(base_samples=base_samples).shape == torch.Size([2, 3, 2]))\n\n    def test_multivariate_normal_batch_correlated_samples_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_multivariate_normal_batch_correlated_samples(cuda=True)\n\n    def test_log_prob(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            mean = torch.randn(4, 3, device=device, dtype=dtype)\n            var = torch.randn(12, device=device, dtype=dtype).abs_()\n            values = mean + 0.5\n            diffs = (values - mean).view(-1)\n\n            res = MultitaskMultivariateNormal(mean, DiagLinearOperator(var)).log_prob(values)\n            actual = -0.5 * (math.log(math.pi * 2) * 12 + var.log().sum() + (diffs / var * diffs).sum())\n            self.assertLess((res - actual).div(res).abs().item(), 1e-2)\n\n            mean = torch.randn(3, 4, 3, device=device, dtype=dtype)\n            var = torch.randn(3, 12, device=device, dtype=dtype).abs_()\n            values = mean + 0.5\n            diffs = (values - mean).view(3, -1)\n\n            res = MultitaskMultivariateNormal(mean, DiagLinearOperator(var)).log_prob(values)\n            actual = -0.5 * (math.log(math.pi * 2) * 12 + var.log().sum(-1) + (diffs / var * diffs).sum(-1))\n            self.assertLess((res - actual).div(res).abs().norm(), 1e-2)\n\n    def test_log_prob_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_log_prob(cuda=True)\n\n    def test_multitask_from_batch(self):\n        mean = torch.randn(2, 3)\n        variance = torch.randn(2, 3).clamp_min(1e-6)\n        mvn = MultivariateNormal(mean, DiagLinearOperator(variance))\n        mmvn = MultitaskMultivariateNormal.from_batch_mvn(mvn, task_dim=-1)\n        self.assertTrue(isinstance(mmvn, MultitaskMultivariateNormal))\n        self.assertEqual(mmvn.batch_shape, torch.Size([]))\n        self.assertEqual(mmvn.event_shape, torch.Size([3, 2]))\n        self.assertEqual(mmvn.covariance_matrix.shape, torch.Size([6, 6]))\n        self.assertEqual(mmvn.mean, mean.transpose(-1, -2))\n        self.assertEqual(mmvn.variance, variance.transpose(-1, -2))\n\n        mean = torch.randn(2, 4, 3)\n        variance = torch.randn(2, 4, 3).clamp_min(1e-6)\n        mvn = MultivariateNormal(mean, DiagLinearOperator(variance))\n        mmvn = MultitaskMultivariateNormal.from_batch_mvn(mvn, task_dim=0)\n        self.assertTrue(isinstance(mmvn, MultitaskMultivariateNormal))\n        self.assertEqual(mmvn.batch_shape, torch.Size([4]))\n        self.assertEqual(mmvn.event_shape, torch.Size([3, 2]))\n        self.assertEqual(mmvn.covariance_matrix.shape, torch.Size([4, 6, 6]))\n        self.assertEqual(mmvn.mean, mean.permute(1, 2, 0))\n        self.assertEqual(mmvn.variance, variance.permute(1, 2, 0))\n\n    def test_multitask_from_repeat(self):\n        mean = torch.randn(2, 3)\n        variance = torch.randn(2, 3).clamp_min(1e-6)\n        mvn = MultivariateNormal(mean, DiagLinearOperator(variance))\n        mmvn = MultitaskMultivariateNormal.from_repeated_mvn(mvn, num_tasks=4)\n        self.assertTrue(isinstance(mmvn, MultitaskMultivariateNormal))\n        self.assertEqual(mmvn.batch_shape, torch.Size([2]))\n        self.assertEqual(mmvn.event_shape, torch.Size([3, 4]))\n        self.assertEqual(mmvn.covariance_matrix.shape, torch.Size([2, 12, 12]))\n        for i in range(4):\n            self.assertEqual(mmvn.mean[..., i], mean)\n            self.assertEqual(mmvn.variance[..., i], variance)\n\n    def test_from_independent_mvns(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        for dtype in (torch.float, torch.double):\n            # Test non-batch mode mvns\n            n_tasks = 2\n            n = 4\n            mvns = [\n                MultivariateNormal(\n                    mean=torch.randn(4, device=device, dtype=dtype),\n                    covariance_matrix=DiagLinearOperator(torch.randn(n, device=device, dtype=dtype).abs_()),\n                )\n                for i in range(n_tasks)\n            ]\n            mvn = MultitaskMultivariateNormal.from_independent_mvns(mvns=mvns)\n            expected_mean_shape = [n, n_tasks]\n            expected_covar_shape = [n * n_tasks] * 2\n            self.assertEqual(list(mvn.mean.shape), expected_mean_shape)\n            self.assertEqual(list(mvn.covariance_matrix.shape), expected_covar_shape)\n\n            # Test batch mode mvns\n            b = 3\n            mvns = [\n                MultivariateNormal(\n                    mean=torch.randn(b, n, device=device, dtype=dtype),\n                    covariance_matrix=DiagLinearOperator(torch.randn(b, n, device=device, dtype=dtype).abs_()),\n                )\n                for i in range(n_tasks)\n            ]\n            mvn = MultitaskMultivariateNormal.from_independent_mvns(mvns=mvns)\n            self.assertEqual(list(mvn.mean.shape), [b] + expected_mean_shape)\n            self.assertEqual(list(mvn.covariance_matrix.shape), [b] + expected_covar_shape)\n\n    def test_from_independent_mvns_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_from_independent_mvns(cuda=True)\n\n    def test_multitask_multivariate_normal_broadcasting(self):\n        mean = torch.randn(5, 1, 3)\n        _covar = torch.randn(6, 6)\n        covar = _covar @ _covar.transpose(-1, -2)\n        sample = MultitaskMultivariateNormal(mean, covar).rsample()\n        self.assertEqual(sample.shape, torch.Size([5, 2, 3]))\n\n        mean = torch.randn(5, 1)\n        _covar = torch.randn(3, 10, 10)\n        covar = _covar @ _covar.transpose(-1, -2)\n        sample = MultitaskMultivariateNormal(mean, covar).rsample()\n        self.assertEqual(sample.shape, torch.Size([3, 5, 2]))\n\n        with self.assertRaises(RuntimeError):\n            mean = torch.randn(5, 1)\n            _covar = torch.randn(12, 12)\n            covar = _covar @ _covar.transpose(-1, -2)\n            MultitaskMultivariateNormal(mean, covar)\n\n\nif __name__ == "__main__":\n    unittest.main()\n',
        }
